// BTItem family barrel — re-exports public API.
export 'item.types.dart';
export 'item.widget.dart';

// BTItem types — Figma source: node 2056-48.

/// Container style variant for [BTItem].
enum BTItemType {
  /// No container styling (no background, no border, no padding).
  defaultType,

  /// Thin border with padding and small border-radius.
  outline,

  /// Subtle background fill with padding and small border-radius.
  muted,
}

/// BTItem — generic list item / row display molecule.
/// Figma source: node 2056-48.
///
/// Three container types: [BTItemType.defaultType] (no chrome),
/// [BTItemType.outline] (border + padding), [BTItemType.muted]
/// (subtle background + padding).
///
/// Optional left media: [leftIcon] widget, [leftAvatar] (renders BTAvatar sm),
/// or [leftImage] URL (32×32 rounded). Priority: avatar > image > icon.
///
/// Optional right content: [rightLabel] text, [rightButton] label
/// (renders BTButton outline sm — takes precedence over rightLabel),
/// and [rightIcon] widget.
///
/// ## Usage:
/// ```dart
/// // Default — avatar + right label
/// BTItem(
///   title: 'Faisal Lestari',
///   description: 'Software Engineer',
///   leftAvatar: BTAvatarItem(name: 'Faisal Lestari', color: BTAvatarColor.blue),
///   rightLabel: 'Admin',
/// )
///
/// // Outline — right button
/// BTItem(
///   type: BTItemType.outline,
///   title: 'Design Token Package',
///   description: 'v2.3.1 — 4 changes',
///   rightButton: 'View',
///   onButtonClick: () => Navigator.push(context, ...),
/// )
///
/// // Muted — right label
/// BTItem(
///   type: BTItemType.muted,
///   title: 'Sprint Review',
///   rightLabel: 'Today',
/// )
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import '../button/button.dart';
import '../avatar/avatar.dart';
import 'package:btech_ui/src/components/molecules/item/item.types.dart';
import 'package:flutter/material.dart';

/// Generic list item row widget — see file header for usage.
class BTItem extends StatelessWidget {
  const BTItem({
    required this.title,
    this.description,
    this.type = BTItemType.defaultType,
    this.leftAvatar,
    this.leftImage,
    this.leftIcon,
    this.rightLabel,
    this.rightButton,
    this.rightIcon,
    this.onButtonClick,
    super.key,
  });

  /// Main title text. Required.
  final String title;

  /// Optional subtitle / description below the title.
  final String? description;

  /// Container style variant. Defaults to [BTItemType.defaultType].
  final BTItemType type;

  /// Avatar payload — renders [BTAvatar] size=sm (32px) on the left.
  /// Highest left-media precedence.
  final BTAvatarItem? leftAvatar;

  /// Any image widget rendered at 32×32 with clipped border-radius.
  /// Use [Image.network], [Image.asset], [SvgPicture.asset], etc.
  /// Second left-media precedence (ignored when [leftAvatar] is set).
  final Widget? leftImage;

  /// Arbitrary widget (typically 16×16 icon) on the left.
  /// Lowest left-media precedence.
  final Widget? leftIcon;

  /// Right side text label. Ignored when [rightButton] is set.
  final String? rightLabel;

  /// Right side button label — renders BTButton outline sm.
  /// Takes precedence over [rightLabel].
  final String? rightButton;

  /// Arbitrary widget (typically 16×16 icon) on the right.
  final Widget? rightIcon;

  /// Called when the right button is tapped.
  final VoidCallback? onButtonClick;

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final r = context.btRadius;

    Widget content = Row(
      crossAxisAlignment: CrossAxisAlignment.center,
      children: [
        // ── Left area ────────────────────────────────────────────────────────
        Expanded(
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.center,
            children: [
              // Avatar (highest precedence)
              if (leftAvatar != null) ...[
                BTAvatar(item: leftAvatar, size: BTAvatarSize.sm),
                SizedBox(width: 8.0),
              ]
              // Image — any widget (Image.network, Image.asset, SvgPicture…)
              else if (leftImage != null) ...[
                ClipRRect(
                  borderRadius: BorderRadius.circular(r.sm),
                  child: SizedBox(
                    width: 32.0,
                    height: 32.0,
                    child: FittedBox(
                      fit: BoxFit.cover,
                      clipBehavior: Clip.hardEdge,
                      child: leftImage,
                    ),
                  ),
                ),
                SizedBox(width: 8.0),
              ]
              // Icon (lowest precedence)
              else if (leftIcon != null) ...[
                SizedBox(width: 16.0, height: 16.0, child: leftIcon),
                SizedBox(width: 8.0),
              ],

              // Title + description
              Expanded(
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    Text(
                      title,
                      style: TextStyle(
                        fontSize: 14.0,
                        fontWeight: FontWeight.w700,
                        color: c.text.primary,
                        height: 16 / 14,
                      ),
                      maxLines: 1,
                      overflow: TextOverflow.ellipsis,
                    ),
                    if (description != null) ...[
                      SizedBox(height: 2.0),
                      Text(
                        description!,
                        style: TextStyle(
                          fontSize: 12.0,
                          fontWeight: FontWeight.w500,
                          color: c.text.secondary,
                          height: 16 / 12,
                        ),
                        maxLines: 1,
                        overflow: TextOverflow.ellipsis,
                      ),
                    ],
                  ],
                ),
              ),
            ],
          ),
        ),

        // ── Right area ───────────────────────────────────────────────────────
        if (rightButton != null || rightLabel != null || rightIcon != null) ...[
          SizedBox(width: 8.0),
          Row(
            mainAxisSize: MainAxisSize.min,
            children: [
              if (rightButton != null)
                BTButton(
                  label: rightButton,
                  variant: BTButtonVariant.outline,
                  size: BTButtonSize.sm,
                  onPressed: onButtonClick,
                )
              else if (rightLabel != null)
                Text(
                  rightLabel!,
                  style: TextStyle(
                    fontSize: 12.0,
                    fontWeight: FontWeight.w500,
                    color: c.text.secondary,
                  ),
                ),
              if (rightIcon != null) ...[
                SizedBox(width: 8.0),
                SizedBox(width: 16.0, height: 16.0, child: rightIcon),
              ],
            ],
          ),
        ],
      ],
    );

    // Apply container decoration for outline / muted variants
    switch (type) {
      case BTItemType.outline:
        content = DecoratedBox(
          decoration: BoxDecoration(
            border: Border.all(color: c.border.primary),
            borderRadius: BorderRadius.circular(r.sm),
          ),
          child: Padding(
            padding: EdgeInsets.all(8.0),
            child: content,
          ),
        );
      case BTItemType.muted:
        content = DecoratedBox(
          decoration: BoxDecoration(
            color: c.bg.subtle,
            borderRadius: BorderRadius.circular(r.sm),
          ),
          child: Padding(
            padding: EdgeInsets.all(8.0),
            child: content,
          ),
        );
      case BTItemType.defaultType:
        break;
    }

    return content;
  }
}
